// HasEmpresa applies the HasEdge predicate on the "empresa" edge.
func HasEmpresa() predicate.Reclamacion {
	return predicate.Reclamacion(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, EmpresaTable, EmpresaColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasEmpresaWith applies the HasEdge predicate on the "empresa" edge with a given conditions (other predicates).
func HasEmpresaWith(preds ...predicate.Empresa) predicate.Reclamacion {
	return predicate.Reclamacion(func(s *sql.Selector) {
		step := newEmpresaStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

// And groups predicates with the AND operator between them.
func And(predicates ...predicate.Reclamacion) predicate.Reclamacion {
	return predicate.Reclamacion(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.Reclamacion) predicate.Reclamacion {
	return predicate.Reclamacion(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.Reclamacion) predicate.Reclamacion {
	return predicate.Reclamacion(sql.NotPredicates(p))
}
